import sys
from collections import defaultdict
input = sys.stdin.readline

def solve():
    n, k = map(int, input().split())
    mines = []
    for _ in range(n):
        x, y, t = map(int, input().split())
        mines.append((x, y, t))

    parent = list(range(n))
    def find(a):
        while parent[a] != a:
            parent[a] = parent[parent[a]]
            a = parent[a]
        return a
    def union(a, b):
        a, b = find(a), find(b)
        if a != b: parent[a] = b

    by_x = defaultdict(list)
    by_y = defaultdict(list)
    for i, (x, y, t) in enumerate(mines):
        by_x[x].append((y, i))
        by_y[y].append((x, i))

    for coord, lst in by_x.items():
        lst.sort()
        for j in range(len(lst)-1):
            if lst[j+1][0] - lst[j][0] <= k:
                union(lst[j][1], lst[j+1][1])
    for coord, lst in by_y.items():
        lst.sort()
        for j in range(len(lst)-1):
            if lst[j+1][0] - lst[j][0] <= k:
                union(lst[j][1], lst[j+1][1])

    comp_min = {}
    for i, (x, y, t) in enumerate(mines):
        r = find(i)
        if r not in comp_min or t < comp_min[r]:
            comp_min[r] = t

    min_timers = sorted(comp_min.values())
    import bisect

    lo, hi = 0, 10**9
    while lo < hi:
        mid = (lo + hi) // 2
        c = len(min_timers) - bisect.bisect_right(min_timers, mid)
        if c <= mid + 1:
            hi = mid
        else:
            lo = mid + 1
    print(lo)

t = int(input())
for _ in range(t):
    input()  # empty line
    solve()
